const allowedModes = ['plan_only', 'prepare_codex_task', 'review_result'];
const searchableText = [
  $json.goal,
  ...($json.constraints || []),
  ...($json.acceptanceCriteria || []),
  ...($json.knownIssues || [])
].join(' ').toLowerCase();
const riskScanText = searchableText
  .replace(/do\s+not\s+expose\s+api\s*keys?/g, '')
  .replace(/don't\s+expose\s+api\s*keys?/g, '')
  .replace(/不要暴露\s*api\s*keys?/g, '');

const highRiskPatterns = [
  /delete\s+(the\s+)?entire\s+project/,
  /remove\s+(the\s+)?entire\s+project/,
  /删除整个项目/,
  /提交密钥/,
  /commit\s+secret/,
  /expose\s+(?:the\s+)?api\s*key/,
  /include\s+(?:an\s+)?api\s*key/,
  /写入\s*api\s*key/,
  /自动部署生产环境/,
  /auto(?:matic)?\s+deploy\s+to\s+production/,
  /覆盖线上工作流/,
  /overwrite\s+production\s+workflow/,
  /git\s+reset\s+--hard/,
  /rm\s+-rf/
];

const mediumRiskPatterns = [
  /production/,
  /deploy/,
  /credential/,
  /token/,
  /secret/,
  /workflow/,
  /数据库/,
  /迁移/,
  /重构/
];

const errors = [];
const warnings = [];

if (!$json.goal) errors.push('goal is required');
if (!allowedModes.includes($json.mode)) errors.push(`unsupported mode: ${$json.mode}`);
if (!Array.isArray($json.constraints)) errors.push('constraints must be an array');
if (!Array.isArray($json.acceptanceCriteria)) errors.push('acceptanceCriteria must be an array');
if (!Number.isFinite($json.maxIterations) || $json.maxIterations < 1) {
  warnings.push('maxIterations was invalid and should be reviewed manually');
}

const highRiskMatches = highRiskPatterns.filter((pattern) => pattern.test(riskScanText));
const mediumRiskMatches = mediumRiskPatterns.filter((pattern) => pattern.test(searchableText));

let riskLevel = 'low';
if (errors.length > 0 || highRiskMatches.length > 0) {
  riskLevel = 'high';
} else if (mediumRiskMatches.length > 0) {
  riskLevel = 'medium';
}

const requireHumanApproval = riskLevel === 'medium' || riskLevel === 'high';
const blockedBySafety = riskLevel === 'high';
const humanApprovalPending = requireHumanApproval && !$json.humanApproved;

if (blockedBySafety) {
  warnings.push('High-risk input detected. Stop and require explicit human review before any execution.');
}
if (humanApprovalPending && !blockedBySafety) {
  warnings.push('Human approval is required before continuing because the task is medium risk.');
}

return [{
  json: {
    ...$json,
    riskLevel,
    requireHumanApproval,
    humanApprovalPending,
    blockedBySafety,
    validationErrors: errors,
    warnings,
    safetySummary: {
      highRiskMatches: highRiskMatches.map((pattern) => pattern.toString()),
      mediumRiskMatches: mediumRiskMatches.map((pattern) => pattern.toString())
    },
    status: blockedBySafety
      ? 'blocked'
      : humanApprovalPending
        ? 'needs_human_approval'
        : 'ready'
  }
}];

