const reviewInput = {
  gitDiffSummary: $json.gitDiffSummary || '',
  testResults: $json.testResults || '',
  changedFiles: Array.isArray($json.changedFiles) ? $json.changedFiles : [],
  codexNotes: $json.codexNotes || '',
  knownIssues: Array.isArray($json.knownIssues) ? $json.knownIssues : []
};

const missingFields = Object.entries(reviewInput)
  .filter(([key, value]) => {
    if (Array.isArray(value)) return value.length === 0 && key !== 'knownIssues';
    return !value && key !== 'knownIssues';
  })
  .map(([key]) => key);

return [{
  json: {
    ...$json,
    reviewInput,
    missingReviewFields: missingFields
  }
}];

const issues = [];
const knownIssues = $json.reviewInput?.knownIssues || [];
const missingFields = $json.missingReviewFields || [];

if (($json.acceptanceCriteria || []).length === 0) {
  issues.push('No acceptance criteria were provided.');
}
if (missingFields.length > 0) {
  issues.push(`Missing review evidence: ${missingFields.join(', ')}`);
}
if (knownIssues.length > 0) {
  issues.push(...knownIssues.map((issue) => `Known issue: ${issue}`));
}

let score = 100;
score -= missingFields.length * 20;
score -= knownIssues.length * 15;
if (($json.acceptanceCriteria || []).length === 0) score -= 20;
score = Math.max(0, score);

const riskyIssueDetected = knownIssues.some((issue) => /secret|token|production|rollback/i.test(issue));
const passed = score >= 80 && issues.length === 0;

let nextAction = 'ask_human';
if (riskyIssueDetected) {
  nextAction = 'rollback';
} else if (!passed) {
  nextAction = 'revise';
}

const nextCodexTaskPrompt = passed
  ? null
  : [
      '# Follow-up Codex Task',
      '',
      `Original goal: ${$json.goal}`,
      '',
      'Please revise the implementation using the findings below:',
      ...issues.map((issue) => `- ${issue}`),
      '',
      'Preserve reversibility, keep the diff small, and report updated validation evidence.'
    ].join('\n');

return [{
  json: {
    ...$json,
    reviewerAgentStatus: 'placeholder',
    reviewerModelRef: '{{ $env.REVIEWER_MODEL }}',
    review: {
      score,
      passed,
      issues,
      nextAction,
      nextCodexTaskPrompt
    },
    status: passed ? 'review_complete' : 'review_needs_attention',
    nextAction,
    nextCodexTaskPrompt
  }
}];
